# Per-million-token prices (USD) — versioned in DB; this is the in-process cache
PRICE_PER_M = {
    "claude-3-5-sonnet": {"input": 3.00, "output": 15.00},
    "claude-3-haiku":    {"input": 0.25, "output": 1.25},
    "text-embedding-3-small": {"input": 0.02, "output": 0.0},
}

def token_cost_usd(call: LLMCall) -> float:
    prices = PRICE_PER_M[call.model]
    return (
        call.input_tokens  / 1_000_000 * prices["input"] +
        call.output_tokens / 1_000_000 * prices["output"]
    )

def turn_cost_usd(turn: ConversationTurn) -> float:
    return sum(token_cost_usd(c) for c in turn.llm_calls)

def conversation_cost_usd(conv: Conversation) -> float:
    return sum(turn_cost_usd(t) for t in conv.turns)

@dataclass
class TaskUnitRecord:
    task_type: str           # "support_ticket" | "code_review" | "doc_draft"
    conversations_used: int  # one task may span multiple conversations
    total_cost_usd: float
    human_time_saved_min: float
    outcome_quality_score: float   # 0..1, from CSAT or rubric eval

    @property
    def cost_per_task_usd(self) -> float:
        return self.total_cost_usd / max(self.conversations_used, 1)

    @property
    def cost_per_minute_saved_usd(self) -> float:
        if self.human_time_saved_min <= 0:
            return float("inf")
        return self.total_cost_usd / self.human_time_saved_min

    @property
    def is_cost_effective(self) -> bool:
        # Efficient if AI cost < 1% of saved human time at $80/hr
        human_cost_saved = self.human_time_saved_min / 60 * 80.0
        return self.total_cost_usd < 0.01 * human_cost_saved

def aggregate_task_unit_costs(
    records: list[TaskUnitRecord],
    task_type: str,
) -> dict:
    subset = [r for r in records if r.task_type == task_type]
    if not subset:
        return {}
    costs = [r.cost_per_task_usd for r in subset]
    return {
        "task_type": task_type,
        "n_tasks": len(subset),
        "avg_cost_per_task_usd": mean(costs),
        "median_cost_per_task_usd": median(costs),
        "pct_cost_effective": sum(1 for r in subset if r.is_cost_effective) / len(subset),
    }

from collections import defaultdict

COST_PER_CONV_TARGET = {
    "support-bot":    0.04,
    "code-assistant": 0.12,
    "doc-drafter":    0.08,
}

def flag_expensive_conversations(
    conversations: list[Conversation],
    multiplier: float = 5.0,
) -> list[tuple[str, float, float]]:
    """Return (conversation_id, cost, threshold) for outlier conversations."""
    results = []
    by_feature: dict[str, list[Conversation]] = defaultdict(list)
    for c in conversations:
        by_feature[c.feature].append(c)

    for feature, convs in by_feature.items():
        costs = [conversation_cost_usd(c) for c in convs]
        threshold = COST_PER_CONV_TARGET.get(feature, mean(costs)) * multiplier
        for c, cost in zip(convs, costs):
            if cost > threshold:
                results.append((c.conversation_id, cost, threshold))
    return results

def check_cost_alerts(
    report: UnitMetricsReport,
    targets: dict[str, float] = COST_PER_CONV_TARGET,
) -> list[str]:
    alerts = []
    target = targets.get(report.feature)
    if target is None:
        return alerts
    ratio = report.cost_per_conversation_usd / target
    if ratio >= 10:
        alerts.append(f"CIRCUIT-BREAK {report.feature}: avg ${report.cost_per_conversation_usd:.4f} is {ratio:.1f}x target")
    elif ratio >= 5:
        alerts.append(f"PAGE {report.feature}: avg ${report.cost_per_conversation_usd:.4f} is {ratio:.1f}x target")
    elif ratio >= 2:
        alerts.append(f"WARN {report.feature}: avg ${report.cost_per_conversation_usd:.4f} is {ratio:.1f}x target")
    if report.p95_cost_usd > target * 5:
        alerts.append(f"WARN {report.feature}: P95 ${report.p95_cost_usd:.4f} exceeds 5x target")
    return alerts
